#include<bits/stdc++.h>
using namespace std;
long long n,a,b,s,v[100010];
long long add,mul;
bool check()
{
    long long now=0,max1=0;
    for(long long i=1;i<=n;i++)
    {
        long long x=v[i]+add;
        now=max(now,0ll)+x;
        max1=max(max1,now);
    }
    return max1>=ceil(s*1.0/mul);
}
int main()
{
    scanf("%lld%lld%lld%lld",&n,&a,&b,&s);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&v[i]);
    }
    long long cnt=0;
    long long ans=LLONG_MAX;
    for(mul=1;mul<=s*5;mul*=2,cnt++)
    {
        long long l=0,r=5e9,best;
        while(l<=r)
        {
            add=(l+r)/2;
            if(check())
            {
                r=add-1;
                best=add;
            }
            else
            {
                l=add+1;
            }
        }
        ans=min(ans,b*cnt+a*best);
    }
    printf("%lld",ans);
    return 0;
}
